mapper.select:
SELECT permission_code
FROM role_permissions
WHERE role_id = #{roleId}

mapper.update:
UPDATE roles
SET role_name = #{roleName}
WHERE role_id = #{roleId}
  AND company_id = #{companyId}

mapper.delete:
DELETE
FROM roles
WHERE role_id = #{roleId}
  AND company_id = #{companyId}

mapper.select:
SELECT COUNT(*)
FROM member_roles
WHERE role_id = #{roleId}

SELECT role_id FROM (
    SELECT role_id
    FROM roles
    WHERE company_id = #{companyId}
      AND role_name = #{roleName}
    ORDER BY role_id
)
WHERE ROWNUM = 1
